I tried implementing the JS Task Runner with Dependencies. This is what it would look like -

```
class Task {
    id: number;
    callback: () => Promise<number | Error>;
    prerequisites: number[];

    constructor(id: number, callback: () => Promise<number | Error>, prerequisites: number[]) {
        this.id = id;
        this.callback = callback;
        this.prerequisites = prerequisites;
    }
};

type TaskResult = {
    id: number;
    result: number | Error;
}

class TaskRunner {
    tasks: {
        [taskId: number]: Task;
    };

    adj: {
        [u: number]: number[];
    }

    indeg: {
        [u: number]: number;
    }

    results: {
        [taskId: number]: number | Error;
    }

    taskQueue: number[];

    taskPromises: Promise<TaskResult>[];

    constructor() {
        this.tasks = {};
        this.adj = {};
        this.indeg = {};
        this.results = {};
        this.taskQueue = [];
        this.taskPromises = [];
    }

    addTask(task: Task): void {
        this.tasks[task.id] = task;
        if(!this.adj[task.id])
            this.adj[task.id] = [];
        if(!this.indeg[task.id])
            this.indeg[task.id] = 0;
        for(let i=0; i<task.prerequisites.length; i++) {
            const neighbours = this.adj[task.prerequisites[i]] ?? [];
            this.adj[task.prerequisites[i]] = [...neighbours, task.id];
            this.indeg[task.id] = (this.indeg[task.id] ?? 0) + 1;
        }
    }

    runTask(task: Task): void {
        this.taskPromises[task.id] = new Promise((resolve, reject) => {
            let prerequisiteTaskPromises = [];
            for(let taskId of task.prerequisites)
                prerequisiteTaskPromises.push(this.taskPromises[taskId]);
            Promise.all(prerequisiteTaskPromises)
                .then(async () => {
                    try {
                        console.log(`Task ${task.id} started!`);
                        let result = await task.callback();
                        this.results[task.id] = result;
                        console.log(`Task ${task.id} successfully completed!`);
                        resolve({id: task.id, result });
                    }
                    catch(e) {
                        this.results[task.id] = e as Error;
                        console.log(`Task ${task.id} threw an error!`);
                        reject({id: task.id, result: e});
                    }
                })
                .catch(e => {
                    this.results[task.id] = e.message;
                    console.log(`Task ${task.id} was not attempted since a pre-requisite task raised an error!`);
                    reject({id: task.id, result: e});
                });
        });
    }

    runTasks() {
        for(let taskId in this.indeg)
            if(this.indeg[+taskId] == 0)
                this.taskQueue.push(+taskId);

        let front = 0;

        while(front < this.taskQueue.length) {
            const frontTaskId = this.taskQueue[front++];
            this.runTask(this.tasks[frontTaskId]);

            for(let i=0; i<this.adj[frontTaskId].length; i++) {
                if(--this.indeg[this.adj[frontTaskId][i]] == 0)
                this.taskQueue.push(this.adj[frontTaskId][i]);
            }
        }

        const allTaskPromises: Promise<TaskResult>[] = [];
        for(let taskPromise of this.taskPromises)
            allTaskPromises.push(taskPromise);

        Promise.allSettled(this.taskPromises).then(() => {
            for(let taskId in this.results) {
                console.log(`Task ${taskId}: Result - ${this.results[+taskId]}`);
            }
        });
    }
};

const makeSuccessTask = (delay: number, value: number): () => Promise<number> => async () => {
    await new Promise((resolve) => setTimeout(resolve, delay));
    return value;
}

const makeFailedTask = (delay: number, error: Error): () => Promise<Error> => async () => {
    await new Promise((resolve) => setTimeout(resolve, delay));
    throw error;
}

const task0 = new Task(0, makeSuccessTask(1000, 0), [5, 4]);
const task1 = new Task(1, makeSuccessTask(2000, 1), [3, 4]);
const task2 = new Task(2, makeFailedTask(100, new Error("Random failure")), [5]);
const task3 = new Task(3, makeSuccessTask(2000, 3), [2]);
const task4 = new Task(4, makeSuccessTask(200, 4), []);
const task5 = new Task(5, makeSuccessTask(1000, 5), []);

const taskRunner = new TaskRunner();
taskRunner.addTask(task0);
taskRunner.addTask(task1);
taskRunner.addTask(task2);
taskRunner.addTask(task3);
taskRunner.addTask(task4);
taskRunner.addTask(task5);

taskRunner.runTasks();

```
